3254:                     tone_case.tone
3255:                 else
3256:                     .level;
3257:                 state.buffer_effective[i] = Span.init_diacritic_tone(s.base, s.diacritic, tone);
3258:             }
3259:             state.buffer_length = @intCast(c.seeds.len);
3260: 
3261:             const trigger = switch (c.trigger_case) {
3262:                 .lower => tone_case.lower_trigger,
3263:                 .upper => tone_case.upper_trigger,
3264:             };
3265: 
3266:             // Setup guard: prevent expected_modification_index from drifting away from seed data.
3267:             try expectEqual(
3268:                 tone_case.tone,
3269:                 state.buffer_effective[c.expected_modification_index].tone,
3270:             );
3271: 
3272:             // Act
3273:             state.add(trigger);
3274: 
3275:             // Assert: the trigger character is appended literally, the matching tone on the seeded
3276:             // vowel is reset to level, and literal_index marks the new literal span.
