3875: // Simple ABI wrapper for initializing allocated memory.
3876: export fn lex_init(state: *anyopaque) void {
3877:     // Pointer must not be null.
3878:     assert(@intFromPtr(state) != 0);
3879:     // Ensure the allocated memory is aligned.
3880:     assert(@intFromPtr(state) % @alignOf(State) == 0);
3881: 
3882:     const s: *State = @ptrCast(@alignCast(state));
3883:     s.init();
3884: }
3885: 
3886: // Needed for the caller to allocate memory for our State.
3887: export const lex_state_size: usize = @sizeOf(State);
3888: 
3889: // Needed for the caller to allocate memory for our State.
3890: export const lex_state_alignment: usize = @alignOf(State);
3891: 
3892: test "expect State can be initialized by raw allocation" {
3893:     // Arrange
3894: 
3895:     // Allocate memory, specified only in this test to simulate runtime allocation.
3896:     const raw_pointer = std.testing.allocator.rawAlloc(lex_state_size, .fromByteUnits(lex_state_alignment), @returnAddress()) orelse return error.OutOfMemory;
3897:     defer std.testing.allocator.rawFree(raw_pointer[0..lex_state_size], .fromByteUnits(lex_state_alignment), @returnAddress());
3898: 
3899:     // Initialize state.
3900:     lex_init(raw_pointer);
3901:     const state: *align(lex_state_alignment) State = @ptrCast(@alignCast(raw_pointer));
3902: 
3903:     const input_sequence = "bbbbbqqqqq";
3904: 
3905:     // Act
3906:     for (input_sequence) |c| {
3907:         lex_add(raw_pointer, c);
3908:     }
3909: 
3910:     // Assert
3911:     // We only fill and increase the buffer_length based on input.
3912:     try expectEqual(10, state.buffer_length);
3913:     // Because we don't modify any existing character since the last input, expect null.
3914:     try expectEqual(null, state.buffer_modification_index);
3915:     // Because we didn't exceed the buffer_effective, don't set literal_index.
3916:     try expectEqual(null, state.literal_index);
3917:     // Verify every span is exactly the same as the input.
3918:     for (input_sequence, 0..) |c, i| {
3919:         const sp = state.buffer_effective[i];
3920:         try expectEqual(c, sp.base);
3921:         try expectEqual(.empty, sp.diacritic);
3922:         try expectEqual(.level, sp.tone);
3923:     }
3924: }
