3926: // Add operations to the given state based on Telex rules, operations are determined by the input
3927: // character.
3928: export fn lex_add(state: *anyopaque, c: u8) void {
3929:     // Pointer must not be null.
3930:     assert(@intFromPtr(state) != 0);
3931:     // Ensure the allocated memory is aligned.
3932:     assert(@intFromPtr(state) % @alignOf(State) == 0);
3933: 
3934:     const s: *State = @ptrCast(@alignCast(state));
3935:     s.add(c);
3936: }
