3938: export fn lex_backspace(state: *anyopaque) void {
3939:     // Pointer must not be null.
3940:     assert(@intFromPtr(state) != 0);
3941:     // Ensure the allocated memory is aligned.
3942:     assert(@intFromPtr(state) % @alignOf(State) == 0);
